var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"아! 스펜서!","JPN":"あっ！　スペンサーさん！","ENG":"Oh! Spencer!","TWN":"啊！史賓瑟！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"살아 계셨네요. 다행이다.","JPN":"生きていたんですね！　よかった。","ENG":"You're alive. I'm so relieved...","TWN":"真是太好了，你還活著！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그쪽이야말로… 괜찮은 거야? 몸 한 가운데 철골이 박혀 있는데?","JPN":"そっちこそ……大丈夫なのか？　体の真ん中に鉄骨が突き刺さっているが……。","ENG":"Are you... all right? There's a steel bar stuck in your midsection.","TWN":"這句話應該是我要說的吧……你還好嗎？你是被鋼筋釘住了？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침식체들에게 잡혀서 죽겠다 싶었는데, 갑자기 굉음이 들리더니 바닥이 무너졌어요.","JPN":"侵食体に捕まって、もうダメかと思ったんですけど、いきなりすごく大きな音がして、地面が崩れ落ちたんです。","ENG":"I thought I was going to die to the C.O.s, but suddenly I heard a roar, and then the floor collapsed.","TWN":"我本來被侵蝕體抓住，還以為自己要死了的，結果突然聽到一聲巨響，地面就塌下來了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"읍- 콜록 콜록-","JPN":"ゴホッ、ゲホッ！　ゲホッ！","ENG":"Ack! *Cough* *Cough*","TWN":"唔——咳咳，咳咳——"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"추락한 뒤로 정신을 차려보니… 이런 꼴이더라고요.","JPN":"転落して気がつくと……こんなふうになってました。","ENG":"When I woke up... this is the shape I was in.","TWN":"等我醒過來的時候……就變成這樣了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"혼자 탈출하려고 해봤는데, 허리 아래로 감각이 없어요.","JPN":"自力で抜け出そうとしたんですけど、腰から下の感覚がなくて。","ENG":"I tried to escape on my own, but I can't feel anything below my waist.","TWN":"我嘗試過自己脫困，但腰部以下什麼也感覺不到。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"철골에 관통되면서 척추신경이 끊어졌을 거야.","JPN":"鉄骨が突き刺さって脊椎の神経が切れてるんだ。","ENG":"The steel bar must have severed your spinal cord.","TWN":"你的脊神經一定是被這根穿透的鋼筋切斷了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지금부터 널 꺼내 줄 건데, 네 톱 좀 빌릴게.","JPN":"今から引っ張り出す。あなたのノコギリを借りるよ？","ENG":"I'll start getting you out of there. I'm gonna borrow your saw for a bit.","TWN":"我現在就帶你出去，借你的電鋸用一下。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"물론이죠. 마음껏 쓰세요.","JPN":"はい、どうぞお好きに使ってください。","ENG":"Of course. Feel free.","TWN":"當然。你隨便用。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그걸로 제 허리를 자르실 건가요?!","JPN":"もしかしてそれで私の腰を切断するんですか！？","ENG":"Are you going to cut my waist off?!","TWN":"你打算用它割斷我的腰嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"끔찍한 소리 마. 철골만 자르려는 거니까.","JPN":"恐ろしいことを言うな。鉄骨だけを切るんだ。","ENG":"Don't be ridiculous. I'm just going to cut the steel bar.","TWN":"別說可怕的話。我只是想切斷那根鋼筋。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"어때? 움직일 수 있겠어?","JPN":"どうだ？　動けるか？","ENG":"How are you? Can you move?","TWN":"怎麼樣？能動了嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"으으… 피를 너무 많이 흘렸나 봐요. 빈혈 때문에 어지러워요.","JPN":"うう……血を流しすぎたせいか、貧血で頭がクラクラします……。","ENG":"Ugh... I must've lost too much blood. I feel dizzy.","TWN":"啊……我可能失血太多了。現在因為貧血有些頭暈。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"빈혈 타령할 정도면, 배에 구멍 난 사람치곤 멀쩡하네.","JPN":"腹に穴が開いたのに貧血とは……その程度なら大丈夫そうだな。","ENG":"If you're complaining about the dizziness, you must be doing all right for someone with a hole in her stomach.","TWN":"你肚子上都多了個洞，你卻覺得只是貧血嗎？那應該沒什麼大礙吧？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"헤헤, 회복은 자신 있거든요.","JPN":"へへ、回復力には自信があるんです。","ENG":"Hehe, I heal pretty fast.","TWN":"嘿嘿，我對自己的自癒能力可是很有信心的。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"쉬어 둬. 카운터의 재생력이 아무리 좋다고 해도 회복할 시간은 필요할 테니까.","JPN":"休んでろ。いくらカウンターの回復が優れていても、一瞬にして治るわけではないからな。","ENG":"Take it easy. Even if Counters have outstanding regeneration abilities, you still need time to recover.","TWN":"好好休息一下吧。無論制裁者的再生能力有多強，恢復都需要時間。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"네! 구해주셔서 감사해요!","JPN":"はいっ！　助けてくださり、ありがとうございます！","ENG":"Okay! Thanks for saving me!","TWN":"嗯！謝謝你救了我！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그런데, 스펜서.","JPN":"ところで、スペンサーさん。","ENG":"But Spencer.","TWN":"不過，史賓瑟。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"좀 전엔 누굴 쫓고 있던 거예요? 발걸음이 한 명은 아닌 것 같던데.","JPN":"さっき誰かを追いかけていませんでしたか？　一人だけの足音ではなかったような気がして。","ENG":"Who were you chasing? I thought I heard more than one footstep.","TWN":"剛才你在追誰嗎？腳步聲聽起來不止一個人。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지난 번에 우릴 구해준 아이야.","JPN":"この間、私たちを助けてくれた子だ。","ENG":"It's the kid who rescued us last time.","TWN":"是上次救了我們的那個孩子。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"말하는 걸 봐선 아무래도 이 시설에 남겨진 실험체였어.","JPN":"少し話したんだが、どうやらこの施設に残された実験体のようだ。","ENG":"I think she must've been one of the test subjects left behind in this facility.","TWN":"聽她說話，很可能是被留在這個設施裡的實驗體。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아무래도 이 시설을 벗어나지 못하도록 세뇌되어 있는 것 같아.","JPN":"その子はこの施設から逃げないように洗脳されていた。","ENG":"She might've been brainwashed to not leave this facility.","TWN":"有人為了防止她離開這個設施，似乎將她給洗腦了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"닮았네요.","JPN":"似ていますね。","ENG":"She's like me.","TWN":"真像啊。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"닮다니… 뭐가?","JPN":"似ている……？　何が？","ENG":"...How so?","TWN":"像……像什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};